const express = require('express');
const session = require('express-session');
const twilio = require('twilio');
const crypto = require('crypto');

const app = express();
const PORT = process.env.PORT || 3000;

// Twilio configuration
const TWILIO_ACCOUNT_SID = process.env.TWILIO_ACCOUNT_SID || 'your_account_sid';
const TWILIO_AUTH_TOKEN = process.env.TWILIO_AUTH_TOKEN || 'your_auth_token';
const TWILIO_PHONE_NUMBER = process.env.TWILIO_PHONE_NUMBER || '+1234567890';

const twilioClient = twilio(TWILIO_ACCOUNT_SID, TWILIO_AUTH_TOKEN);

// In-memory store for 2FA codes
const twoFactorStore = new Map();

// Code expiration time (5 minutes)
const CODE_EXPIRATION_MS = 5 * 60 * 1000;
const MAX_ATTEMPTS = 3;
const RATE_LIMIT_MS = 60 * 1000; // 1 minute between resends

// Simulated user database
const users = new Map([
  ['user1', { id: 'user1', username: 'john', password: 'password123', phone: '+1234567890', twoFactorEnabled: true }],
  ['user2', { id: 'user2', username: 'jane', password: 'password456', phone: '+0987654321', twoFactorEnabled: true }],
]);

// Middleware
app.use(express.json());
app.use(express.urlencoded({ extended: true }));
app.use(session({
  secret: process.env.SESSION_SECRET || 'your-super-secret-session-key-change-in-production',
  resave: false,
  saveUninitialized: false,
  cookie: {
    secure: process.env.NODE_ENV === 'production',
    httpOnly: true,
    maxAge: 30 * 60 * 1000, // 30 minutes
    sameSite: 'strict'
  }
}));

// Helper: Generate a random 6-digit code
function generateCode() {
  return crypto.randomInt(100000, 999999).toString();
}

// Helper: Store 2FA code for a user
function storeCode(userId, code) {
  twoFactorStore.set(userId, {
    code,
    createdAt: Date.now(),
    attempts: 0,
    verified: false
  });
}

// Helper: Get stored code data
function getStoredCode(userId) {
  return twoFactorStore.get(userId);
}

// Helper: Clean up expired codes periodically
function cleanupExpiredCodes() {
  const now = Date.now();
  for (const [userId, data] of twoFactorStore.entries()) {
    if (now - data.createdAt > CODE_EXPIRATION_MS) {
      twoFactorStore.delete(userId);
    }
  }
}

setInterval(cleanupExpiredCodes, 60 * 1000);

// Helper: Send SMS via Twilio
async function sendSMS(phoneNumber, message) {
  try {
    const result = await twilioClient.messages.create({
      body: message,
      from: TWILIO_PHONE_NUMBER,
      to: phoneNumber
    });
    console.log(`SMS sent successfully. SID: ${result.sid}`);
    return { success: true, sid: result.sid };
  } catch (error) {
    console.error('Failed to send SMS:', error.message);
    return { success: false, error: error.message };
  }
}

// Helper: Mask phone number for display
function maskPhoneNumber(phone) {
  if (!phone || phone.length < 4) return '****';
  return '***' + phone.slice(-4);
}

// Middleware: Check if user is authenticated (step 1 - password)
function requirePasswordAuth(req, res, next) {
  if (!req.session.userId || !req.session.passwordVerified) {
    return res.status(401).json({
      success: false,
      message: 'Please log in first with your username and password.'
    });
  }
  next();
}

// Middleware: Check if user is fully authenticated (both factors)
function requireFullAuth(req, res, next) {
  if (!req.session.userId || !req.session.passwordVerified) {
    return res.status(401).json({
      success: false,
      message: 'Please log in first.'
    });
  }
  if (!req.session.twoFactorVerified) {
    return res.status(403).json({
      success: false,
      message: 'Two-factor authentication required. Please verify your code.'
    });
  }
  next();
}

