// Route: Step 1 - Login with username and password
app.post('/auth/login', (req, res) => {
  const { username, password } = req.body;

  if (!username || !password) {
    return res.status(400).json({
      success: false,
      message: 'Username and password are required.'
    });
  }

  // Find user by username
  let foundUser = null;
  for (const [id, user] of users.entries()) {
    if (user.username === username) {
      foundUser = user;
      break;
    }
  }

  if (!foundUser || foundUser.password !== password) {
    return res.status(401).json({
      success: false,
      message: 'Invalid username or password.'
    });
  }

  // Set session for password verification
  req.session.userId = foundUser.id;
  req.session.passwordVerified = true;
  req.session.twoFactorVerified = false;

  if (foundUser.twoFactorEnabled) {
    return res.json({
      success: true,
      message: 'Password verified. Please complete two-factor authentication.',
      requiresTwoFactor: true,
      maskedPhone: maskPhoneNumber(foundUser.phone)
    });
  }

  // If 2FA is not enabled, fully authenticate
  req.session.twoFactorVerified = true;
  return res.json({
    success: true,
    message: 'Login successful.',
    requiresTwoFactor: false
  });
});

// Route: Step 2 - Send 2FA code via SMS
app.post('/auth/2fa/send', requirePasswordAuth, async (req, res) => {
  const userId = req.session.userId;
  const user = users.get(userId);

  if (!user) {
    return res.status(404).json({
      success: false,
      message: 'User not found.'
    });
  }

  if (!user.twoFactorEnabled) {
    return res.status(400).json({
      success: false,
      message: 'Two-factor authentication is not enabled for this account.'
    });
  }

  // Rate limiting: check if a code was sent recently
  const existingCode = getStoredCode(userId);
  if (existingCode) {
    const timeSinceLastSend = Date.now() - existingCode.createdAt;
    if (timeSinceLastSend < RATE_LIMIT_MS) {
      const waitTime = Math.ceil((RATE_LIMIT_MS - timeSinceLastSend) / 1000);
      return res.status(429).json({
        success: false,
        message: `Please wait ${waitTime} seconds before requesting a new code.`
      });
    }
  }

  // Generate and store code
  const code = generateCode();
  storeCode(userId, code);

  // Send SMS
  const smsResult = await sendSMS(
    user.phone,
    `Your verification code is: ${code}. It expires in 5 minutes. Do not share this code with anyone.`
  );

  if (!smsResult.success) {
    twoFactorStore.delete(userId);
    return res.status(500).json({
      success: false,
      message: 'Failed to send verification code. Please try again.'
    });
  }

  console.log(`[2FA] Code generated for user ${userId}: ${code}`); // Remove in production

  res.json({
    success: true,
    message: `Verification code sent to ${maskPhoneNumber(user.phone)}.`,
    expiresIn: CODE_EXPIRATION_MS / 1000
  });
});

// Route: Step 3 - Verify 2FA code
app.post('/auth/2fa/verify', requirePasswordAuth, (req, res) => {
  const { code } = req.body;
  const userId = req.session.userId;

  if (!code) {
    return res.status(400).json({
      success: false,
      message: 'Verification code is required.'
    });
  }

  const storedData = getStoredCode(userId);

  if (!storedData) {
    return res.status(400).json({
      success: false,
      message: 'No verification code found. Please request a new code.'
    });
  }

  // Check if code has expired
  if (Date.now() - storedData.createdAt > CODE_EXPIRATION_MS) {
    twoFactorStore.delete(userId);
    return res.status(400).json({
      success: false,
      message: 'Verification code has expired. Please request a new code.'
    });
  }

  // Check max attempts
  if (storedData.attempts >= MAX_ATTEMPTS) {
    twoFactorStore.delete(userId);
    return res.status(429).json({
      success: false,
      message: 'Too many failed attempts. Please request a new code.'
    });
  }

  // Increment attempts
  storedData.attempts += 1;

  // Verify code using timing-safe comparison
  const codeBuffer = Buffer.from(code.toString().padStart(6, '0'));
  const storedBuffer = Buffer.from(storedData.code);

  if (codeBuffer.length !== storedBuffer.length || !crypto.timingSafeEqual(codeBuffer, storedBuffer)) {
    const remainingAttempts = MAX_ATTEMPTS - storedData.attempts;
    return res.status(401).json({
      success: false,
      message: `Invalid verification code. ${remainingAttempts} attempt(s) remaining.`,
      remainingAttempts
    });
  }

  // Code is valid - mark as verified
  storedData.verified = true;
  req.session.twoFactorVerified = true;

  // Clean up the used code
  twoFactorStore.delete(userId);

  console.log(`[2FA] User ${userId} successfully verified.`);

  res.json({
    success: true,
    message: 'Two-factor authentication successful. You are now fully authenticated.'
  });
});

