// Route: Check authentication status
app.get('/auth/status', (req, res) => {
  const isPasswordVerified = !!req.session.passwordVerified;
  const isTwoFactorVerified = !!req.session.twoFactorVerified;
  const isFullyAuthenticated = isPasswordVerified && isTwoFactorVerified;

  res.json({
    success: true,
    authenticated: isFullyAuthenticated,
    passwordVerified: isPasswordVerified,
    twoFactorVerified: isTwoFactorVerified,
    userId: req.session.userId || null
  });
});

// Route: Logout
app.post('/auth/logout', (req, res) => {
  const userId = req.session.userId;

  // Clean up any stored codes
  if (userId) {
    twoFactorStore.delete(userId);
  }

  req.session.destroy((err) => {
    if (err) {
      console.error('Session destruction error:', err);
      return res.status(500).json({
        success: false,
        message: 'Failed to logout.'
      });
    }

    res.clearCookie('connect.sid');
    res.json({
      success: true,
      message: 'Logged out successfully.'
    });
  });
});

// Route: Enable/Disable 2FA for a user
app.post('/auth/2fa/toggle', requireFullAuth, (req, res) => {
  const userId = req.session.userId;
  const user = users.get(userId);

  if (!user) {
    return res.status(404).json({
      success: false,
      message: 'User not found.'
    });
  }

  user.twoFactorEnabled = !user.twoFactorEnabled;

  res.json({
    success: true,
    message: `Two-factor authentication ${user.twoFactorEnabled ? 'enabled' : 'disabled'}.`,
    twoFactorEnabled: user.twoFactorEnabled
  });
});

